from typing import List, Optional

class Solution:
    def buildTree(self, preorder: List[int], inorder: List[int]):
        if not preorder:
            return None
        in_map = {val: i for i, val in enumerate(inorder)}
        root = TreeNode(preorder[0])
        stack = [root]
        for i in range(1, len(preorder)):
            node = TreeNode(preorder[i])
            if in_map[preorder[i]] < in_map[stack[-1].val]:
                stack[-1].left = node
            else:
                parent = None
                while stack and in_map[stack[-1].val] < in_map[preorder[i]]:
                    parent = stack.pop()
                parent.right = node
            stack.append(node)
        return root
